// // This module implements a synchronous full adder with an enable signal. When the enable signal (En) is high, the module computes the sum and carry-out outputs using standard full adder logic; specifically, it calculates the sum by XORing inputs A, B, and Cin, and generates the carry-out using a combination of AND and OR operations. However, when the enable signal is low, both the sum and carry-out outputs are set to one, effectively enabling the adder functionality.
module top_module(
    input A,
    input B,
    input Cin,
    input En,
    output reg Sum,
    output reg Cout
);always @(A or B or Cin or En) begin
    if (En == 1'b1) begin
        Sum  <= A ^ B ^ Cin;
        Cout <= (A & B) | (Cin & (A ^ B));
    end else begin
        Sum  <= 1'b0;
        Cout <= 1'b0;
    end
end

endmodule
